@startuml
!theme plain

title ENTITIES's Class Diagram

package "il" as il {
  package "ac" as ac {
    package "afeka" as afeka {
      package "tomco" as tomco {
        package "cookingapp" as cookingapp {
          package "Entities" as Entities {
            class "CategoriesContent" as CategoriesContent {
              + CATEGORIES : List<Category>
              - clear()
              - addCategory()
            }

            class "RecipesContent" as RecipesContent {
              + RECIPES : List<Recipe>
              - clear()
              - addRecipe()
            }

            class "Category" as Category {
              + title : String
              + imageURL : String
              - CREATOR : Creator<Category>
              - Category()
              - Category()
              - Category()
              - setTitle()
              - setImageURL()
              - getTitle()
              - getImageURL()
              - describeContents()
              - writeToParcel()
            }

            class "Recipe" as Recipe {
              + title : String
              + ingredients : String
              + cookingOperations : String
              + category : String
              + imageURL : String
              + uploadingUser : String
              - CREATOR : Creator<Recipe>
              - Recipe()
              - Recipe()
              - Recipe()
              - getTitle()
              - setTitle()
              - getIngredients()
              - setIngredients()
              - getCookingOperations()
              - setCookingOperations()
              - getImageURL()
              - setImageURL()
              - getCategory()
              - setCategory()
              - getUploadingUser()
              - setUploadingUser()
              - describeContents()
              - writeToParcel()
            }

            class "UploadImage" as UploadImage {
              + name : String
              + imageURL : String
              - UploadImage()
              - UploadImage()
              - getName()
              - setName()
              - getImageUrl()
              - setImageUrl()
            }
          }
        }
      }
    }
  }
}

class "Parcelable" as Parcelable {
  + Parcelable()
}

Category ..> Parcelable
Recipe ..> Parcelable

@enduml
